# --- Configuration ---
my $PLUGIN_DIR = $ENV{PLUGIN_DIR} || './plugins';
my $ALLOWED_PLUGINS_FILE = $ENV{ALLOWED_PLUGINS} || './allowed_plugins.conf';
my $MAX_PLUGIN_SIZE = 10_000;  # Maximum plugin file size in bytes
