# --- Security: Allowlist of approved plugin checksums ---
my %APPROVED_CHECKSUMS;

sub load_approved_checksums {
    my ($checksum_file) = @_;
    unless (-f $checksum_file) {
        warn "Warning: Approved plugins file '$checksum_file' not found. No plugins will be authorized.\n";
        return;
    }
    open my $fh, '<', $checksum_file
        or croak "Cannot open approved plugins file '$checksum_file': $!";
    while (my $line = <$fh>) {
        chomp $line;
        next if $line =~ /^\s*#/ || $line =~ /^\s*$/;
        if ($line =~ /^([a-f0-9]{64})\s+(.+)$/) {
            $APPROVED_CHECKSUMS{$2} = $1;
        }
    }
    close $fh;
}

# --- Security: Validate plugin code against dangerous patterns ---
sub validate_plugin_code {
    my ($code, $plugin_name) = @_;

    my @forbidden_patterns = (
        qr/\bsystem\s*\(/,
        qr/\bexec\s*\(/,
        qr/\bqx\s*[\{\(\[\/]/,
        qr/`[^`]*`/,
        qr/\bopen\s*\(\s*\w+\s*,\s*["']\s*\|/,       # open pipe
        qr/\|\s*["']\s*\)/,                              # pipe at end of open
        qr/\brequire\s+/,
        qr/\buse\s+/,
        qr/\bdo\s+["']/,
        qr/\bBEGIN\s*\{/,
        qr/\bINIT\s*\{/,
        qr/\bCHECK\s*\{/,
        qr/\bUNITIMPORT\b/,
        qr/\bunlink\s*\(/,
        qr/\brmdir\s*\(/,
        qr/\brename\s*\(/,
        qr/\bchmod\s*\(/,
        qr/\bchown\s*\(/,
        qr/\bkill\s*\(/,
        qr/\bfork\s*\(/,
        qr/\bsocket\s*\(/,
        qr/\bconnect\s*\(/,
        qr/\bbind\s*\(/,
        qr/\blisten\s*\(/,
        qr/\baccept\s*\(/,
        qr/\beval\s*\(/,                                 # No nested eval
        qr/\beval\s*\{/,
        qr/\bENV\s*\{/,
        qr/\bGLOB\b/,
        qr/\bSymbol\b/,
        qr/\bSCALAR\s*\{/,
        qr/\bARRAY\s*\{/,
        qr/\bHASH\s*\{/,
        qr/\bCODE\s*\{/,
    );

    for my $pattern (@forbidden_patterns) {
        if ($code =~ $pattern) {
            warn "SECURITY: Plugin '$plugin_name' contains forbidden pattern: $pattern\n";
            return 0;
        }
    }

    return 1;
}

# --- Security: Verify file integrity via checksum ---
sub verify_checksum {
    my ($code, $plugin_name) = @_;
    my $checksum = sha256_hex($code);
    my $expected = $APPROVED_CHECKSUMS{$plugin_name};

    unless (defined $expected) {
        warn "SECURITY: Plugin '$plugin_name' is not in the approved plugins list.\n";
        return 0;
    }

    unless ($checksum eq $expected) {
        warn "SECURITY: Plugin '$plugin_name' checksum mismatch.\n";
        warn "  Expected: $expected\n";
        warn "  Got:      $checksum\n";
        return 0;
    }

    return 1;
}

# --- Security: Validate plugin file path ---
sub validate_plugin_path {
    my ($filepath) = @_;

    # Resolve to absolute path and ensure it's within PLUGIN_DIR
    use Cwd qw(abs_path);
    my $abs_plugin_dir = abs_path($PLUGIN_DIR);
    my $abs_filepath = abs_path($filepath);

    unless (defined $abs_filepath && defined $abs_plugin_dir) {
        warn "SECURITY: Cannot resolve path for '$filepath'.\n";
        return 0;
    }

    unless ($abs_filepath =~ /^\Q$abs_plugin_dir\E/) {
        warn "SECURITY: Plugin path '$filepath' is outside allowed directory.\n";
        return 0;
    }

    # Only allow .pl extension
    unless ($abs_filepath =~ /\.pl$/) {
        warn "SECURITY: Plugin '$filepath' does not have .pl extension.\n";
        return 0;
    }

    return 1;
}

# --- Load a plugin file safely ---
sub load_plugin_code {
    my ($filepath) = @_;

    unless (-f $filepath && -r $filepath) {
        warn "Plugin file '$filepath' does not exist or is not readable.\n";
        return undef;
    }

    my $filesize = -s $filepath;
    if ($filesize > $MAX_PLUGIN_SIZE) {
        warn "SECURITY: Plugin '$filepath' exceeds maximum size ($filesize > $MAX_PLUGIN_SIZE bytes).\n";
        return undef;
    }

    open my $fh, '<', $filepath
        or do { warn "Cannot open plugin '$filepath': $!\n"; return undef; };
    local $/;
    my $code = <$fh>;
    close $fh;

    return $code;
}

# --- Execute a validated plugin in a restricted namespace ---
sub execute_plugin {
    my ($plugin_name, $code, $context) = @_;

    # Wrap the plugin code in a restricted package namespace
    my $safe_package = "PluginSandbox::$plugin_name";
    $safe_package =~ s/[^A-Za-z0-9_:]/_/g;

    my $wrapped_code = qq{
        package $safe_package;
        use strict;
        use warnings;
        no warnings 'redefine';

        sub run_plugin {
            my (\$ctx) = \@_;
            $code
        }
        1;
    };

    # Execute with eval - only after all security checks have passed
    my $compile_result = eval($wrapped_code);  ## no critic - intentional eval for plugin system, code is validated above
    if ($@) {
        warn "Plugin '$plugin_name' compilation error: $@\n";
        return { success => 0, error => "Compilation failed: $@" };
    }

    # Call the plugin's run_plugin function
    my $run_func = "${safe_package}::run_plugin";
    my $result;
    {
        no strict 'refs';
        local $SIG{ALRM} = sub { die "Plugin execution timeout\n" };
        alarm(5);  # 5 second timeout
        eval {
            $result = $run_func->($context);
        };
        alarm(0);
    }

    if ($@) {
        warn "Plugin '$plugin_name' runtime error: $@\n";
        return { success => 0, error => "Runtime error: $@" };
    }

    return { success => 1, result => $result };
}

# --- Main plugin loading and execution pipeline ---
sub load_and_run_plugin {
    my ($plugin_name, $context) = @_;

    print "=" x 60, "\n";
    print "Loading plugin: $plugin_name\n";
    print "=" x 60, "\n";

    # Step 1: Construct and validate path
    my $filepath = "$PLUGIN_DIR/$plugin_name.pl";
    unless (validate_plugin_path($filepath)) {
        return { success => 0, error => "Path validation failed" };
    }
    print "[OK] Path validation passed.\n";

    # Step 2: Load the code
    my $code = load_plugin_code($filepath);
    unless (defined $code) {
        return { success => 0, error => "Failed to load plugin code" };
    }
    print "[OK] Plugin code loaded (", length($code), " bytes).\n";

    # Step 3: Verify checksum against approved list
    unless (verify_checksum($code, $plugin_name)) {
        return { success => 0, error => "Checksum verification failed" };
    }
    print "[OK] Checksum verification passed.\n";

    # Step 4: Validate code patterns
    unless (validate_plugin_code($code, $plugin_name)) {
        return { success => 0, error => "Code validation failed - forbidden patterns detected" };
    }
    print "[OK] Code pattern validation passed.\n";

    # Step 5: Execute in sandbox
    print "[..] Executing plugin...\n";
    my $result = execute_plugin($plugin_name, $code, $context);

    if ($result->{success}) {
        print "[OK] Plugin executed successfully.\n";
    } else {
        print "[FAIL] Plugin execution failed: $result->{error}\n";
    }

    return $result;
}

# --- Utility: Generate checksum for a plugin file (for building allowlist) ---
sub generate_plugin_checksum {
    my ($plugin_name) = @_;
    my $filepath = "$PLUGIN_DIR/$plugin_name.pl";
    my $code = load_plugin_code($filepath);
    return unless defined $code;
    my $checksum = sha256_hex($code);
    print "$checksum  $plugin_name\n";
    return $checksum;
}

